class Solution:
    def maximumEvenSplit(self, finalSum: int) -> List[int]:
        if finalSum % 2 != 0:
            return []
        res = []
        i = 2
        while finalSum > 0:
            if finalSum - i >= i:
                res.append(i)
                finalSum -= i
                i += 2
            else:
                res.append(finalSum)
                break
        return res

